import aiocoap
from aiocoap import Context, Message, Code

async def handle_sensor_temp(request):
    if request.code == Code.GET:
        # Simulate reading temperature sensor
        temp = 25.0
        response = Message(code=Code.CONTENT, payload=str(temp).encode())
        return response
    elif request.code == Code.PUT:
        try:
            new_temp = float(request.payload.decode())
            # Simulate setting temperature sensor
            print(f"Setting temperature to {new_temp}")
            response = Message(code=Code.CHANGED)
            return response
        except ValueError:
            response = Message(code=Code.BAD_REQUEST, payload=b"Invalid temperature value")
            return response

async def handle_actuator_light(request):
    if request.code == Code.GET:
        # Simulate reading light actuator state
        state = "ON"
        response = Message(code=Code.CONTENT, payload=state.encode())
        return response
    elif request.code == Code.PUT:
        try:
            new_state = request.payload.decode()
            if new_state in ["ON", "OFF"]:
                # Simulate setting light actuator state
                print(f"Setting light to {new_state}")
                response = Message(code=Code.CHANGED)
                return response
            else:
                response = Message(code=Code.BAD_REQUEST, payload=b"Invalid state value")
                return response
        except ValueError:
            response = Message(code=Code.BAD_REQUEST, payload=b"Invalid state value")
            return response

async def main():
    context = await Context.create_server_context()

    # Register resources
    context.request_handlers["/sensors/temp"] = handle_sensor_temp
    context.request_handlers["/actuators/light"] = handle_actuator_light

    print("CoAP server started, listening for requests...")
    await context.start()

if __name__ == "__main__":
    import asyncio
    asyncio.run(main())